<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Maze Bot Explorer</title>
<style>
  body{font-family:Arial,sans-serif;margin:0;padding:20px;background:#fafafa;}
  #controls{margin-bottom:10px;}
  #maze{border:1px solid #333;display:block;width:400px;height:400px;}
  .info{margin-right:15px;}
</style>
</head>
<body>
<div id="controls">
  <span class="info">Completed: <span id="completed">0</span>/24</span>
  <span class="info">Timer: <span id="timer">0</span></span>
  <button id="reset">Reset</button>
</div>
<canvas id="maze" width="400" height="400"></canvas>

<script>
(() => {
const canvas=document.getElementById('maze');
const ctx=canvas.getContext('2d');
const completedEl=document.getElementById('completed');
const timerEl=document.getElementById('timer');
const resetBtn=document.getElementById('reset');

class Maze{
  constructor(rows,cols,seed){
    this.rows=rows;this.cols=cols;
    this.seed=seed||Math.random();
    this.walls=this.initWalls();
    this.generate();
  }
  initWalls(){
    const w=[];
    for(let r=0;r<this.rows;r++){
      w[r]=[];
      for(let c=0;c<this.cols;c++){
        w[r][c]={n:true,e:true,s:true,w:true};
      }
    }
    return w;
  }
  rand(){return Math.floor(Math.random()*this.seed);}
  generate(){
    const stack=[[0,0]];
    const visited=new Set();
    while(stack.length){
      const [r,c]=stack[stack.length-1];
      visited.add(r*this.cols+c);
      const dirs=[{n:-1,w:0},{e:0,s:1},{s:1,e:0},{w:0,n:-1}];
      let moved=false;
      for(const d of dirs){
        const nr=r+d.n||r, nc=c+d.e||c;
        if(nr>=0&&nr<this.rows&&nc>=0&&nc<this.cols&&!visited.has(nr*this.cols+nc)){
          this.walls[r][c][d.n!==undefined?'n':'e'] = false;
          this.walls[nr][nc][d.s!==undefined?'s':'w']=false;
          stack.push([nr,nc]);moved=true;break;
        }
      }
      if(!moved)stack.pop();
    }
  }
}

class Bot{
  constructor(id,maze,start){
    this.id=id;
    this.maze=maze;
    this.pos={...start};
    this.path=[{...this.pos}];
    this.deadEnds=[];
    this.finishTick=null;
    this.dirOrder=this.randomDirOrder();
    this.stack=[[this.pos]];
    this.visited=new Set([this.key(this.pos)]);
  }
  key(p){return `${p.r},${p.c}`;}
  randomDirOrder(){
    const dirs=['n','e','s','w'];
    for(let i=dirs.length-1;i>0;--i){
      const j=Math.floor(Math.random()* (i+1));
      [dirs[i],dirs[j]]=[dirs[j],dirs[i]];
    }
    return dirs;
  }
  step(){
    if(this.finishTick!==null)return;
    while(this.stack.length){
      const cur=this.stack[this.stack.length-1];
      let moved=false;
      for(const d of this.dirOrder){
        const nr=cur.r+(d==='n'?-1:d==='s'?1:0);
        const nc=cur.c+(d==='w'?-1:d==='e'?1:0);
        if(nr<0||nr>=this.maze.rows||nc<0||nc>=this.maze.cols)continue;
        if(this.maze.walls[cur.r][cur.c][d])continue;
        const key=this.key({r:nr,c:nc});
        if(!this.visited.has(key)){
          this.visited.add(key);
          this.pos={r:nr,c:nc};
          this.path.push({...this.pos});
          this.stack.push(this.pos);
          moved=true;break;
        }
      }
      if(!moved){
        const dead=this.stack.pop();
        this.deadEnds.push(dead);
      }else break;
    }
  }
}

class Game{
  constructor(seed){
    this.seed=seed||Math.random();
    this.size={rows:15,cols:15};
    this.maze=new Maze(this.size.rows,this.size.cols,this.seed);
    this.spawn={r:0,c:0};
    this.exit={r:this.size.rows-1,c:this.size.cols-1};
    this.bots=[];
    for(let i=0;i<24;i++){
      const bot=new Bot(i,this.maze,this.spawn);
      this.bots.push(bot);
    }
    this.elapsed=0;
    this.lastFinish=null;
  }
  tick(n){
    for(let t=0;t<n;t++){
      if(this.lastFinish!==null)break;
      for(const b of this.bots){b.step();}
      const finished=this.bots.filter(b=>!b.finishTick);
      if(finished.length===0){
        this.lastFinish=this.elapsed+1;
        break;
      }
      this.elapsed++;
    }
  }
  reset(seed){
    this.seed=seed||Math.random();
    this.maze=new Maze(this.size.rows,this.size.cols,this.seed);
    this.bots=[];
    for(let i=0;i<24;i++){
      const bot=new Bot(i,this.maze,this.spawn);
      this.bots.push(bot);
    }
    this.elapsed=0;
    this.lastFinish=null;
  }
}

const game=new Game();
window.game={};

Object.defineProperty(window.game,'elapsed',{get(){return game.elapsed;}});

Object.defineProperty(window.game,'size',{get(){return game.size;}});

Object.defineProperty(window.game,'spawn',{get(){return game.spawn;}});

Object.defineProperty(window.game,'exit',{get(){return game.exit;}});

window.game.walls=(r,c)=>game.maze.walls[r][c];

Object.defineProperty(window.game,'bots',{
  get(){
    return game.bots.map(b=>({
      path:b.path,
      deadEnds:b.deadEnds,
      finishTick:b.finishTick
    }));
  }
});

window.game.tick=n=>{
  game.tick(n);
  render();
};

window.game.reset=seed=>{
  game.reset(seed);
  render();
};

function render(){
  const {rows,cols}=game.size;
  const cellW=canvas.width/cols;
  const cellH=canvas.height/rows;
  ctx.clearRect(0,0,canvas.width,canvas.height);
  // walls
  ctx.strokeStyle='#000';
  for(let r=0;r<rows;r++){
    for(let c=0;c<cols;c++){
      const w=game.maze.walls[r][c];
      if(w.n)ctx.moveTo(c*cellW,r*cellH);else ctx.moveTo((c+1)*cellW,r*cellH);
      if(w.e)ctx.lineTo((c+1)*cellW,(r+1)*cellH);else ctx.lineTo((c+1)*cellW,r*cellH);
      if(w.s)ctx.lineTo(c*cellW,(r+1)*cellH);else ctx.lineTo((c+1)*cellW,(r+1)*cellH);
      if(w.w)ctx.lineTo(c*cellW,r*cellH);else ctx.lineTo(c*cellW,(r+1)*cellH);
    }
  }
  ctx.stroke();
  // exit
  ctx.fillStyle='green';
  ctx.beginPath();ctx.arc((game.exit.c+0.5)*cellW,(game.exit.r+0.5)*cellH,cellW/4,0,Math.PI*2);ctx.fill();
  // bots
  for(const b of game.bots){
    const pos=b.pos;
    ctx.fillStyle=`hsl(${b.id*15},70%,50%)`;
    ctx.beginPath();ctx.arc((pos.c+0.5)*cellW,(pos.r+0.5)*cellH,cellW/6,0,Math.PI*2);ctx.fill();
  }
  // stats
  completedEl.textContent=game.bots.filter(b=>b.finishTick!==null).length;
  timerEl.textContent=game.elapsed;
}
render();

resetBtn.onclick(()=>{window.game.reset();});

})();
</script>
</body>
</html>
